module edge_detector(
    input clk,
    input reset,
    input signal,
    output reg edge_detected
);

    reg unused_signal_delayed;

    always @(posedge clk) begin
        if (reset) begin
            unused_signal_delayed <= 0;
            edge_detected <= 0;
        end else begin
            edge_detected <= signal & ~unused_signal_delayed;
            unused_signal_delayed <= signal;
        end
    end

endmodule
